/* ========== ThingsBoard Custom Widget - 智慧农业大棚数字孪生监控 ========== */

.tb-app-container {
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    background: #020b12;
    font-family: 'Segoe UI', 'PingFang SC', 'Microsoft YaHei', sans-serif;
    color: #e0f0ff;
    overflow: hidden;
}

/* ========== 顶部标题栏 ========== */
.tb-header {
    height: 7vh;
    min-height: 48px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 2vw;
    background: linear-gradient(90deg, rgba(0,0,0,0.6) 0%, rgba(0,30,50,0.4) 50%, rgba(0,0,0,0.6) 100%);
    border-bottom: 1px solid rgba(0, 217, 255, 0.15);
    position: relative;
    z-index: 200;
}

.tb-header::after {
    content: '';
    position: absolute;
    bottom: -1px;
    left: 20%;
    right: 20%;
    height: 1px;
    background: linear-gradient(90deg, transparent, #00d9ff, transparent);
}

.tb-header-left { display: flex; align-items: center; gap: 1vw; }

.tb-live-badge {
    padding: 0.2vh 0.8vw;
    background: rgba(53, 242, 143, 0.15);
    border: 1px solid rgba(53, 242, 143, 0.4);
    color: #35f28f;
    font-size: 1.8vh;
    font-weight: 700;
    letter-spacing: 2px;
    border-radius: 3px;
    animation: tb-live-pulse 2s ease-in-out infinite;
}

@keyframes tb-live-pulse {
    0%, 100% { opacity: 0.7; }
    50% { opacity: 1; }
}

.tb-header-title {
    font-size: 2.8vh;
    font-weight: 600;
    letter-spacing: 2px;
    color: #e0f0ff;
    text-shadow: 0 0 15px rgba(0, 217, 255, 0.3);
    margin: 0;
}

.tb-header-center { display: flex; gap: 2vw; }

.tb-header-stat { display: flex; align-items: center; gap: 0.6vw; }

.tb-stat-label {
    font-size: 1.4vh;
    color: #4a6a80;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.tb-stat-value {
    font-size: 1.5vh;
    font-weight: 600;
    padding: 0.3vh 0.8vw;
    background: rgba(0,0,0,0.3);
    border: 1px solid rgba(0, 217, 255, 0.15);
    border-radius: 3px;
    color: #7a9ab0;
}

.tb-status-online {
    color: #35f28f;
    border-color: rgba(53, 242, 143, 0.3);
    background: rgba(53, 242, 143, 0.1);
}

.tb-header-right {
    display: flex;
    align-items: center;
    gap: 1.2vw;
}

.tb-header-time {
    font-family: 'Courier New', monospace;
    font-size: 2vh;
    color: #00d9ff;
    text-shadow: 0 0 8px rgba(0, 217, 255, 0.4);
}

/* ========== 主场景 ========== */
.tb-greenhouse-stage {
    position: relative;
    flex: 1;
    width: 100%;
    overflow: hidden;
    background: #020b12;
}

.tb-greenhouse-bg {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: opacity 0.8s ease;
}

.tb-greenhouse-bg.tb-night-bg { opacity: 0; }
.tb-greenhouse-stage.night-mode .tb-night-bg { opacity: 1; }
.tb-greenhouse-stage.day-mode .tb-day-bg { opacity: 1; }
.tb-greenhouse-stage.day-mode .tb-night-bg { opacity: 0; }

/* ========== 特效层 ========== */
.tb-effects-layer {
    position: absolute;
    inset: 0;
    pointer-events: none;
    z-index: 10;
}

/* 补光灯 */
.tb-lamp-glow {
    position: absolute;
    opacity: 0;
    transition: opacity 0.5s ease;
    background: linear-gradient(180deg, rgba(255,255,220,0) 0%, rgba(255,245,180,0.75) 30%, rgba(255,220,120,0.35) 70%, transparent 100%);
    filter: blur(8px);
    border-radius: 999px;
    box-shadow: 0 0 18px rgba(255,245,180,0.6), 0 0 42px rgba(255,220,120,0.35), 0 0 80px rgba(0,220,255,0.15);
}

.tb-lamp-glow.active {
    opacity: 0.75;
    animation: tb-lamp-breathe 2.5s ease-in-out infinite;
}

.tb-greenhouse-stage.night-mode .tb-lamp-glow.active {
    opacity: 1;
    filter: blur(10px);
    box-shadow: 0 0 25px rgba(255,250,210,0.9), 0 0 65px rgba(255,220,120,0.7), 0 0 110px rgba(0,220,255,0.35);
}

@keyframes tb-lamp-breathe {
    0%, 100% { opacity: 0.6; }
    50% { opacity: 1; }
}

.tb-lamp-glow-left-main {
    left: 8%;
    top: 16%;
    width: 16%;
    height: 12%;
    transform: rotate(15deg);
    transform-origin: center top;
}

.tb-lamp-glow-right-main {
    left: 78%;
    top: 16%;
    width: 16%;
    height: 12%;
    transform: rotate(-15deg);
    transform-origin: center top;
}

.tb-lamp-glow-left-mid {
    left: 27%;
    top: 35%;
    width: 10%;
    height: 8%;
    transform: rotate(25deg);
    transform-origin: center top;
}

.tb-lamp-glow-right-mid {
    left: 64%;
    top: 35%;
    width: 10%;
    height: 8%;
    transform: rotate(-25deg);
    transform-origin: center top;
}

/* 风扇 */
.tb-fan-effect {
    position: absolute;
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: opacity 0.3s;
}

.tb-fan-effect.active { opacity: 1; }

.tb-fan-blade {
    width: 100%;
    height: 100%;
    border-radius: 50%;
    border: 2px solid rgba(0, 217, 255, 0.4);
    position: relative;
}

.tb-fan-blade::before,
.tb-fan-blade::after {
    content: '';
    position: absolute;
    border-radius: 50%;
}

.tb-fan-blade::before { inset: 15%; border: 1px solid rgba(0, 217, 255, 0.3); }
.tb-fan-blade::after { inset: 35%; background: rgba(0, 217, 255, 0.15); }

.tb-fan-effect.active .tb-fan-blade { animation: tb-fan-spin 0.5s linear infinite; }

.tb-fan-blade-small {
    width: 100%;
    height: 100%;
    border-radius: 50%;
    border: 1.5px solid rgba(0, 217, 255, 0.35);
}

.tb-fan-blade-small::before {
    content: '';
    position: absolute;
    inset: 20%;
    border-radius: 50%;
    border: 1px solid rgba(0, 217, 255, 0.25);
}

.tb-fan-effect.active .tb-fan-blade-small { animation: tb-fan-spin 0.6s linear infinite; }

@keyframes tb-fan-spin {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
}

.tb-fan-effect-left { left: 16.75%; top: 31%; width: 5.5%; height: 8%; }
.tb-fan-effect-right { left: 77.75%; top: 31%; width: 5.5%; height: 8%; }
.tb-fan-effect-left-back { left: 33.25%; top: 36.5%; width: 3.5%; height: 5%; }
.tb-fan-effect-right-back { left: 63.25%; top: 36.5%; width: 3.5%; height: 5%; }

/* 喷淋 */
.tb-spray-effect {
    position: absolute;
    width: 42%;
    height: 36%;
    opacity: 0;
    pointer-events: none;
    transform-origin: top center;
    transition: opacity 0.25s ease;
}

.tb-spray-effect.active { opacity: 1; }

.tb-water-line {
    position: absolute;
    left: 50%;
    top: 0;
    width: 1.5px;
    height: var(--length);
    background: linear-gradient(to bottom, rgba(220,250,255,0.95), rgba(80,210,255,0.65), rgba(80,210,255,0));
    box-shadow: 0 0 6px rgba(80,220,255,0.8);
    transform-origin: top center;
    transform: translateX(var(--x-offset)) rotate(var(--angle));
    animation: tb-water-line-pulse 0.9s linear infinite;
    animation-delay: var(--delay);
}

.tb-water-particle {
    position: absolute;
    left: 50%;
    top: 0;
    width: var(--size);
    height: var(--size);
    border-radius: 50%;
    background: rgba(170,240,255,0.9);
    box-shadow: 0 0 8px rgba(100,220,255,0.75);
    animation: tb-water-particle-move 1.1s linear infinite;
    animation-delay: var(--delay);
}

@keyframes tb-water-line-pulse {
    0% { opacity: 0; transform: translateX(var(--x-offset)) rotate(var(--angle)) scaleY(0.45); }
    35% { opacity: 0.95; }
    100% { opacity: 0.1; transform: translateX(var(--x-offset)) rotate(var(--angle)) scaleY(1); }
}

@keyframes tb-water-particle-move {
    0% { opacity: 0; transform: rotate(var(--angle)) translateY(0); }
    20% { opacity: 1; }
    100% { opacity: 0; transform: rotate(var(--angle)) translateY(var(--distance)); }
}

.tb-spray-left-front { left: -8%; top: 48%; width: 42%; height: 36%; }
.tb-spray-left-mid { left: 10%; top: 52%; width: 38%; height: 32%; }
.tb-spray-right-mid { left: 52%; top: 52%; width: 38%; height: 32%; }
.tb-spray-right-front { left: 66%; top: 48%; width: 42%; height: 36%; }

/* 管道 */
.tb-pipe-flow {
    position: absolute;
    opacity: 0;
    transition: opacity 0.5s;
    background: rgba(0, 217, 255, 0.15);
    box-shadow: 0 0 10px rgba(0, 217, 255, 0.2);
}

.tb-pipe-flow.active { opacity: 1; }

.tb-pipe-flow-left { left: 0%; top: 40%; width: 47%; height: 0.6%; }
.tb-pipe-flow-right { left: 53%; top: 40%; width: 47%; height: 0.6%; }

/* 土壤告警 */
.tb-soil-warning-area {
    position: absolute;
    left: 7%;
    top: 54%;
    width: 86%;
    height: 38%;
    background: rgba(255, 149, 0, 0.08);
    border: 1px solid rgba(255, 149, 0, 0.2);
    opacity: 0;
    transition: opacity 0.5s;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 4px;
    pointer-events: none;
}

.tb-soil-warning-area.active {
    opacity: 1;
    animation: tb-soil-alert 2s ease-in-out infinite;
}

@keyframes tb-soil-alert {
    0%, 100% { border-color: rgba(255, 149, 0, 0.15); }
    50% { border-color: rgba(255, 149, 0, 0.4); }
}

.tb-soil-warning-text {
    font-size: 1.8vh;
    color: #ff9500;
    font-weight: 600;
    text-shadow: 0 0 10px rgba(255, 149, 0, 0.4);
    padding: 1vh 2vw;
    background: rgba(0,0,0,0.5);
    border-radius: 4px;
    border: 1px solid rgba(255, 149, 0, 0.3);
}

/* 中央标签 */
.tb-center-tag {
    position: absolute;
    left: 42%;
    top: 43%;
    width: 16%;
    height: 6%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.4vh;
    color: #00d9ff;
    opacity: 0;
    transition: opacity 0.3s;
}

.tb-center-tag.active { opacity: 1; }

.tb-center-tag::before {
    content: attr(data-text);
    padding: 0.5vh 1vw;
    background: rgba(0,0,0,0.5);
    border: 1px solid rgba(0, 217, 255, 0.2);
    border-radius: 3px;
    white-space: nowrap;
}

/* ========== UI层 ========== */
.tb-ui-layer {
    position: absolute;
    inset: 0;
    pointer-events: none;
    z-index: 20;
}

.tb-ui-layer > * { pointer-events: auto; }

/* 右侧仪表盘 */
.tb-right-dashboard {
    position: absolute;
    right: 1.5%;
    top: 10%;
    width: 20%;
    height: 82%;
    display: flex;
    flex-direction: column;
    gap: 12px;
    pointer-events: auto;
    overflow: hidden;
    z-index: 25;
}

/* 面板 */
.tb-side-panel {
    position: relative;
    background: rgba(3, 18, 28, 0.78);
    border: 1px solid rgba(0, 220, 255, 0.28);
    border-radius: 8px;
    backdrop-filter: blur(10px);
    overflow: hidden;
}

.tb-side-panel::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 2px;
    background: linear-gradient(90deg, transparent, #00d9ff, transparent);
}

.tb-panel-header {
    display: flex;
    align-items: center;
    gap: 0.5vw;
    padding: 1vh 1vw;
    border-bottom: 1px solid rgba(0, 217, 255, 0.15);
}

.tb-panel-icon { font-size: 1.6vh; }

.tb-panel-title {
    font-size: 1.4vh;
    font-weight: 600;
    color: #7a9ab0;
    letter-spacing: 1px;
}

.tb-panel-body { padding: 1vh 1vw; }

/* 环境监测 */
.tb-env-panel {
    flex: 1;
    min-height: 0;
    overflow-y: auto;
}

.tb-env-panel::-webkit-scrollbar { width: 6px; }
.tb-env-panel::-webkit-scrollbar-thumb { background: rgba(0, 220, 255, 0.45); border-radius: 4px; }

.tb-env-card {
    background: rgba(0,0,0,0.2);
    border: 1px solid rgba(0,217,255,0.1);
    border-radius: 5px;
    padding: 1vh 0.8vw;
    margin-bottom: 0.8vh;
    position: relative;
    transition: all 0.3s;
}

.tb-env-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 3px;
    height: 100%;
    background: #00d9ff;
    opacity: 0.5;
    border-radius: 5px 0 0 5px;
}

.tb-env-tag { font-size: 1vh; color: #00d9ff; opacity: 0.7; letter-spacing: 1px; }
.tb-env-value { font-size: 2.6vh; font-weight: 700; color: #e0f0ff; line-height: 1.1; text-shadow: 0 0 8px rgba(0, 217, 255, 0.2); }
.tb-env-unit { font-size: 1vh; color: #7a9ab0; display: inline; margin-left: 0.3vw; }
.tb-env-name { font-size: 1.1vh; color: #7a9ab0; margin-top: 0.3vh; }

.tb-env-card.tb-warning { border-left-color: #ff9500; }
.tb-env-card.tb-warning .tb-env-value { color: #ff9500; }
.tb-env-card.tb-danger { border-left-color: #ff3860; }
.tb-env-card.tb-danger .tb-env-value { color: #ff3860; }

/* 水位条 */
.tb-water-level-bar {
    height: 3px;
    background: rgba(255,255,255,0.1);
    border-radius: 2px;
    margin-top: 0.5vh;
    overflow: hidden;
}

.tb-water-level-fill {
    height: 100%;
    width: 80%;
    background: linear-gradient(90deg, #00a8e8, #00d9ff);
    border-radius: 2px;
    transition: width 0.5s, background 0.3s;
}

.tb-water-level-fill.tb-low {
    background: linear-gradient(90deg, #ff3860, #ff9500);
}

/* 报警面板 */
.tb-alarm-panel {
    flex: 0 0 auto;
    max-height: 28%;
    overflow-y: auto;
}

.tb-alarm-panel::-webkit-scrollbar { width: 6px; }
.tb-alarm-panel::-webkit-scrollbar-thumb { background: rgba(0, 220, 255, 0.45); border-radius: 4px; }

.tb-alarm-row {
    display: flex;
    align-items: center;
    gap: 0.6vw;
    padding: 0.8vh 0.6vw;
    border-radius: 4px;
    background: rgba(0,0,0,0.2);
    margin-bottom: 0.5vh;
    transition: all 0.3s;
}

.tb-alarm-row.tb-alert {
    background: rgba(255, 56, 96, 0.1);
    border: 1px solid rgba(255, 56, 96, 0.25);
    animation: tb-alarm-blink 2s ease-in-out infinite;
}

@keyframes tb-alarm-blink {
    0%, 100% { border-color: rgba(255,56,96,0.15); }
    50% { border-color: rgba(255,56,96,0.4); }
}

.tb-alarm-led {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: #35f28f;
    box-shadow: 0 0 4px #35f28f;
    flex-shrink: 0;
}

.tb-alarm-row.tb-alert .tb-alarm-led {
    background: #ff3860;
    box-shadow: 0 0 6px #ff3860;
    animation: tb-led-blink 1s ease-in-out infinite;
}

@keyframes tb-led-blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.3; }
}

.tb-alarm-name { flex: 1; font-size: 1.2vh; color: #7a9ab0; }
.tb-alarm-text { font-size: 1.1vh; color: #35f28f; font-weight: 600; }
.tb-alarm-row.tb-alert .tb-alarm-text { color: #ff3860; }

/* 底部状态条 */
.tb-bottom-bar {
    position: absolute;
    left: 18%;
    bottom: 2%;
    width: 64%;
    height: 5.5vh;
    min-height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 3vw;
    background: rgba(3, 18, 28, 0.78);
    border: 1px solid rgba(0, 220, 255, 0.28);
    border-radius: 8px;
    backdrop-filter: blur(10px);
}

.tb-bottom-bar::before {
    content: '';
    position: absolute;
    top: 0;
    left: 10%;
    right: 10%;
    height: 1px;
    background: linear-gradient(90deg, transparent, #00d9ff, transparent);
}

.tb-device-status { display: flex; align-items: center; gap: 0.6vw; }

.tb-device-led {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #1a3a2a;
    box-shadow: inset 0 0 2px rgba(0,0,0,0.5);
    transition: all 0.3s;
    flex-shrink: 0;
}

.tb-device-led.tb-on { background: #35f28f; box-shadow: 0 0 8px #35f28f, inset 0 0 2px rgba(255,255,255,0.3); }
.tb-device-led.tb-on-blue { background: #00a8e8; box-shadow: 0 0 8px #00a8e8; }
.tb-device-led.tb-on-yellow { background: #ffe066; box-shadow: 0 0 8px #ffe066; }
.tb-device-led.tb-on-cyan { background: #00d9ff; box-shadow: 0 0 8px #00d9ff; }
.tb-device-led.tb-on-orange { background: #ff9500; box-shadow: 0 0 8px #ff9500; }

.tb-device-name { font-size: 1.3vh; color: #7a9ab0; }
.tb-device-state { font-size: 1.2vh; color: #7a9ab0; font-family: 'Courier New', monospace; }
.tb-device-state.tb-on { color: #35f28f; }

/* ========== 演示场景按钮 ========== */
.tb-mock-buttons {
    position: absolute;
    left: 1.5%;
    bottom: 2%;
    display: flex;
    flex-direction: column;
    gap: 7px;
    z-index: 30;
    pointer-events: auto;
}

.tb-mock-btn {
    padding: 7px 13px;
    background: rgba(3, 18, 28, 0.48);
    border: 1px solid rgba(0, 220, 255, 0.17);
    color: #7a9ab0;
    font-size: 1.25vh;
    border-radius: 5px;
    cursor: pointer;
    transition: all 0.3s;
    backdrop-filter: blur(6px);
    white-space: nowrap;
    font-family: inherit;
    text-align: left;
}

.tb-mock-btn:hover {
    background: rgba(0, 220, 255, 0.1);
    border-color: rgba(0, 220, 255, 0.35);
    color: #c0e0f0;
}

.tb-mock-btn.active {
    background: rgba(0, 220, 255, 0.15);
    border-color: rgba(0, 220, 255, 0.5);
    color: #00d9ff;
    box-shadow: 0 0 12px rgba(0, 220, 255, 0.18);
}

.tb-mock-btn-restore {
    margin-top: 4px;
    border-color: rgba(53, 242, 143, 0.25);
    color: #5a8a70;
}

.tb-mock-btn-restore:hover {
    background: rgba(53, 242, 143, 0.08);
    border-color: rgba(53, 242, 143, 0.4);
    color: #35f28f;
}

/* 响应式 */
@media (max-width: 1280px) {
    .tb-right-dashboard { width: 22%; }
    .tb-header-title { font-size: 2.2vh; }
}

@media (max-width: 768px) {
    .tb-header-center { display: none; }
    .tb-right-dashboard { width: 28%; }
    .tb-bottom-bar { left: 5%; width: 90%; gap: 1.5vw; }
}

descriptor.controllerScript:
/**
 * 智慧农业大棚数字孪生监控 - ThingsBoard Custom Widget
 *
 * 适配 ThingsBoard CE 4.3.0.1 Custom Widget
 * 从 ctx.data 读取遥测数据，驱动大棚场景动画
 */

// ========== 配置区 ==========
const CONFIG = {
    // 图片 URL 配置 - 请根据实际情况修改
    // 方案1：放在 ThingsBoard 服务器静态目录
    // dayImage: '/static/greenhouse_day.png',
    // nightImage: '/static/greenhouse_night.png',

    // 方案2：独立静态文件服务器
    // dayImage: 'http://192.168.161.130:9000/greenhouse_day.png',
    // nightImage: 'http://192.168.161.130:9000/greenhouse_night.png',

    // 方案：Windows 本地静态服务器
    dayImage: 'http://192.168.161.1:9000/greenhouse_day.png',
    nightImage: 'http://192.168.161.1:9000/greenhouse_night.png',

    // 是否启用演示模式（显示左下角按钮）
    demoMode: false,

    // 数据刷新间隔 (ms)
    refreshInterval: 3000
};

// ========== Mock 演示数据 ==========
const mockScenarios = {
    normalDay: {
        temperature: 24.8, airHumidity: 49.3, soilHumidity: 43.0,
        lightIntensity: 600, co2: 641, waterLevel: 80,
        fanStatus: false, pumpStatus: false, lampStatus: false,
        sprayStatus: false, autoMode: false,
        soilAlarm: false, tempAlarm: false, waterAlarm: false, co2Alarm: false
    },
    nightLamp: {
        temperature: 22.5, airHumidity: 58.0, soilHumidity: 45.0,
        lightIntensity: 100, co2: 620, waterLevel: 78,
        fanStatus: false, pumpStatus: false, lampStatus: true,
        sprayStatus: false, autoMode: true,
        soilAlarm: false, tempAlarm: false, waterAlarm: false, co2Alarm: false
    },
    irrigation: {
        temperature: 27.5, airHumidity: 52.0, soilHumidity: 22.0,
        lightIntensity: 500, co2: 700, waterLevel: 75,
        fanStatus: false, pumpStatus: true, lampStatus: false,
        sprayStatus: true, autoMode: true,
        soilAlarm: true, tempAlarm: false, waterAlarm: false, co2Alarm: false
    },
    lowWater: {
        temperature: 28.0, airHumidity: 50.0, soilHumidity: 20.0,
        lightIntensity: 500, co2: 690, waterLevel: 10,
        fanStatus: false, pumpStatus: false, lampStatus: false,
        sprayStatus: false, autoMode: true,
        soilAlarm: true, tempAlarm: false, waterAlarm: true, co2Alarm: false
    }
};

// ========== 状态变量 ==========
let sceneMode = 'day';
let currentScenario = 'normalDay';
let currentData = {};
let demoMode = false;
let els = {};
let refreshTimer = null;

// ========== 从 ThingsBoard 读取数据 ==========
function getLatestValue(ctx, key, defaultValue) {
    if (!ctx || !ctx.data) return defaultValue;

    for (const item of ctx.data) {
        if (item.dataKey && item.dataKey.name === key) {
            if (item.data && item.data.length > 0) {
                const lastEntry = item.data[item.data.length - 1];
                return lastEntry.length > 1 ? lastEntry[1] : defaultValue;
            }
        }
    }
    return defaultValue;
}

function parseBool(value) {
    return value === true || value === 'true' || value === 1 || value === '1' || value === 'True';
}

function readTelemetryData(ctx) {
    return {
        temperature: Number(getLatestValue(ctx, 'temperature', 0)),
        airHumidity: Number(getLatestValue(ctx, 'airHumidity', 0)),
        soilHumidity: Number(getLatestValue(ctx, 'soilHumidity', 0)),
        lightIntensity: Number(getLatestValue(ctx, 'lightIntensity', 0)),
        co2: Number(getLatestValue(ctx, 'co2', 0)),
        waterLevel: Number(getLatestValue(ctx, 'waterLevel', 0)),
        fanStatus: parseBool(getLatestValue(ctx, 'fanStatus', false)),
        pumpStatus: parseBool(getLatestValue(ctx, 'pumpStatus', false)),
        lampStatus: parseBool(getLatestValue(ctx, 'lampStatus', false)),
        sprayStatus: parseBool(getLatestValue(ctx, 'sprayStatus', false)),
        autoMode: parseBool(getLatestValue(ctx, 'autoMode', false)),
        soilAlarm: parseBool(getLatestValue(ctx, 'soilAlarm', false)),
        tempAlarm: parseBool(getLatestValue(ctx, 'tempAlarm', false)),
        waterAlarm: parseBool(getLatestValue(ctx, 'waterAlarm', false)),
        co2Alarm: parseBool(getLatestValue(ctx, 'co2Alarm', false))
    };
}

// ========== 动态生成喷淋粒子 ==========
function createSprayParticles(container, lineCount, particleCount) {
    if (!container) return;
    container.innerHTML = '';

    for (let i = 0; i < lineCount; i++) {
        const line = document.createElement('span');
        line.className = 'tb-water-line';
        line.style.setProperty('--angle', `${-65 + Math.random() * 130}deg`);
        line.style.setProperty('--length', `${28 + Math.random() * 22}%`);
        line.style.setProperty('--delay', `${Math.random() * 0.8}s`);
        line.style.setProperty('--x-offset', `${-6 + Math.random() * 12}px`);
        container.appendChild(line);
    }

    for (let i = 0; i < particleCount; i++) {
        const p = document.createElement('span');
        p.className = 'tb-water-particle';
        p.style.setProperty('--angle', `${-70 + Math.random() * 140}deg`);
        p.style.setProperty('--distance', `${90 + Math.random() * 180}px`);
        p.style.setProperty('--delay', `${Math.random() * 1.2}s`);
        p.style.setProperty('--size', `${1 + Math.random() * 2.5}px`);
        container.appendChild(p);
    }
}

